// Test stackalloc with native-sized integers (nint / nuint)

Span<nint> signedSpan = stackalloc nint[4];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = i * 10;

Console.WriteLine($"Span<nint> length: {signedSpan.Length}, element size: {sizeof(nint)} bytes");
for (int i = 0; i < signedSpan.Length; i++)
    Console.WriteLine($"  signedSpan[{i}] = {signedSpan[i]}");

Span<nuint> unsignedSpan = stackalloc nuint[3];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i + 100);

Console.WriteLine($"\nSpan<nuint> length: {unsignedSpan.Length}, element size: {sizeof(nuint)} bytes");
for (int i = 0; i < unsignedSpan.Length; i++)
    Console.WriteLine($"  unsignedSpan[{i}] = {unsignedSpan[i]}");

Console.WriteLine("\n✓ stackalloc with nint/nuint works!");

